      <script>
      (function() {
          'use strict';
          
          // Complete list of problematic resources and error patterns
          const problematicPatterns = [
              'wap/upload/products/',
              'upload/slider/',
              'notification.mp3',
              'livetrafficfeed.com',
              'google-analytics.com',
              'googlesyndication.com',
